-- Pairs unit rows with the engine `land_units` key emitted by the rpfm
-- scraper.  Without this seed, parsed `.replay` files cannot join their
-- per-unit keys (e.g. `wh_main_emp_inf_halberdiers`) back to a unit row,
-- so the post-match modal can only show the raw key.
--
-- Long-term this file should be generated by the scraper alongside the
-- existing seed-<faction>-units.sql files; until then it is hand-curated
-- to cover the units that appear in the bundled e2e fixture replays.
--
-- Single CASE-based UPDATE so the file is one statement (next.jdbc's
-- execute! only runs the first statement of a multi-statement string).
--
-- TODO(scraper): emit this file from rpfm-scraper using the existing
-- name_match.clj data so every unit gets a key, not just the demo set.
UPDATE unit
SET key = CASE eid
  -- ── Empire ────────────────────────────────────────────────────────────
  WHEN '00010024-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_halberdiers'
  WHEN '00010022-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_greatswords'
  WHEN '00010027-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_spearmen_0'
  WHEN '00010028-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_spearmen_1'
  WHEN '00010032-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_handgunners'
  WHEN '0001002e-0000-4000-8000-000000000000' THEN 'wh_main_emp_inf_crossbowmen'
  WHEN '00010033-0000-4000-8000-000000000000' THEN 'wh3_dlc25_emp_inf_hochland_long_rifles'
  WHEN '0001002d-0000-4000-8000-000000000000' THEN 'wh2_dlc13_emp_inf_archers_0'
  WHEN '0001002f-0000-4000-8000-000000000000' THEN 'wh2_dlc13_emp_inf_archers_ror_0'
  WHEN '0001002b-0000-4000-8000-000000000000' THEN 'wh_dlc04_emp_inf_tattersouls_0'
  WHEN '0001003f-0000-4000-8000-000000000000' THEN 'wh3_dlc25_emp_cav_knights_of_the_black_rose'
  WHEN '00010044-0000-4000-8000-000000000000' THEN 'wh_dlc04_emp_cav_zintlers_reiksguard_0'
  WHEN '00010045-0000-4000-8000-000000000000' THEN 'wh_main_emp_cav_outriders_0'
  WHEN '0001004e-0000-4000-8000-000000000000' THEN 'wh_main_emp_art_helblaster_volley_gun'
  WHEN '0001005c-0000-4000-8000-000000000000' THEN 'wh2_dlc13_emp_veh_war_wagon_1'
  WHEN '00010009-0000-4000-8000-000000000000' THEN 'wh3_dlc25_emp_cha_master_engineer_steam_tank'
  -- ── Chaos Dwarfs ──────────────────────────────────────────────────────
  WHEN '00040010-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_chaos_dwarf_warriors'
  WHEN '00040011-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_chaos_dwarf_warriors_great_weapons'
  WHEN '00040013-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_hobgoblin_cutthroats'
  WHEN '00040018-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_orc_labourers'
  WHEN '0004001b-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_chaos_dwarf_blunderbusses'
  WHEN '0004001c-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_inf_hobgoblin_archers'
  WHEN '00040024-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_cav_hobgoblin_wolf_raiders_spears'
  WHEN '00040023-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_cav_hobgoblin_wolf_raiders_ror'
  WHEN '0004002d-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_veh_skullcracker'
  WHEN '00040036-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_mon_great_taurus'
  WHEN '0004000e-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_cha_gorduz_backstabber'
  WHEN '00040004-0000-4000-8000-000000000000' THEN 'wh3_dlc23_chd_cha_sorcerer_prophet_fire_great_taurus'
  WHEN '00040028-0000-4000-8000-000000000000' THEN 'wh_pro04_chs_art_hellcannon_ror_0'
  ELSE key
END;
